tool_calls:
mkdir -p /release
awk '
BEGIN { feat_n=0; fix_n=0; oth_n=0 }
{
  if (match($0, /^([^()]+)\(([^)]*)\):[[:space:]]*(.*)$/, m)) {
    type = m[1];
    scope = m[2];
    msg = m[3];
    item = "- " scope ": " msg;

    if (type == "feat") {
      feat[++feat_n] = item;
    } else if (type == "fix") {
      fix[++fix_n] = item;
    } else {
      oth[++oth_n] = item;
    }
  }
}
END {
  print "## Features";
  for (i = 1; i <= feat_n; i++) print feat[i];
  print "";

  print "## Bug Fixes";
  for (i = 1; i <= fix_n; i++) print fix[i];
  print "";

  print "## Other";
  for (i = 1; i <= oth_n; i++) print oth[i];
}
' /data/commits.log > /release/CHANGELOG.md

cat /release/CHANGELOG.md

